mapper.select:
SELECT 
  FROM refund_policy
 WHERE policy_code = #{policyCode}
 ORDER BY version DESC, id DESC
 LIMIT #{limit}

SELECT COALESCE(MAX(version), 0)
  FROM refund_policy
 WHERE policy_code = #{policyCode}

SELECT trigger_type
  FROM refund_policy_acknowledgement
 WHERE user_id = #{userId}
   AND refund_policy_id = #{policyId}
 ORDER BY id

SELECT EXISTS(
    SELECT 1
      FROM refund_policy_acknowledgement
     WHERE user_id = #{userId}
       AND refund_policy_id = #{policyId}
       AND trigger_type = #{triggerType}
       AND action_key = #{actionKey}
)
